DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20250906211712_InitialPostgreSQLMigrationFixed') THEN
    PERFORM setval(
        pg_get_serial_sequence('"Drinks"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "Drinks") + 1,
            nextval(pg_get_serial_sequence('"Drinks"', 'Id'))),
        false);
    PERFORM setval(
        pg_get_serial_sequence('"Events"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "Events") + 1,
            nextval(pg_get_serial_sequence('"Events"', 'Id'))),
        false);
    PERFORM setval(
        pg_get_serial_sequence('"StadiumSeats"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "StadiumSeats") + 1,
            nextval(pg_get_serial_sequence('"StadiumSeats"', 'Id'))),
        false);
    PERFORM setval(
        pg_get_serial_sequence('"StadiumSections"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "StadiumSections") + 1,
            nextval(pg_get_serial_sequence('"StadiumSections"', 'Id'))),
        false);
    PERFORM setval(
        pg_get_serial_sequence('"Users"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "Users") + 1,
            nextval(pg_get_serial_sequence('"Users"', 'Id'))),
        false);
    PERFORM setval(
        pg_get_serial_sequence('"Seats"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "Seats") + 1,
            nextval(pg_get_serial_sequence('"Seats"', 'Id'))),
        false);
    PERFORM setval(
        pg_get_serial_sequence('"Tickets"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "Tickets") + 1,
            nextval(pg_get_serial_sequence('"Tickets"', 'Id'))),
        false);
    END IF;
END $EF$;

